if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first().json.body || {};
const prompt = body.prompt || '';
const outputFormat = (body.outputFormat || 'pptx').toLowerCase();
const templateType = body.templateType || 'general';
const sources = body.sources || [];

if (!prompt) {
  throw new Error('Missing required field: prompt');
}

const validFormats = ['pptx', 'pdf', 'docx'];
if (!validFormats.includes(outputFormat)) {
  throw new Error(`Invalid outputFormat: ${outputFormat}. Must be one of: ${validFormats.join(', ')}`);
}

return [{
  json: {
    prompt,
    outputFormat,
    templateType,
    sources,
    timestamp: new Date().toISOString()
  }
}];

const matches = $input.first().json.matches || [];
const prevData = $('Validate Input').first().json;

const contextChunks = matches
  .filter(m => m.score > 0.7)
  .map(m => {
    const meta = m.metadata || {};
    return `[Source: ${meta.filename || 'unknown'}, Page: ${meta.page || 'n/a'}]\n${meta.text || ''}`;
  });

const context = contextChunks.join('\n\n---\n\n');

return [{
  json: {
    ...prevData,
    ragContext: context,
    sourceCount: contextChunks.length
  }
}];

